import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const { referral_code, new_customer_id } = await req.json();
    if (!referral_code || !new_customer_id) {
      return new Response(
        JSON.stringify({ error: 'Missing referral_code or new_customer_id' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Find the referral
    const { data: referral } = await supabase
      .from('referrals')
      .select('*')
      .eq('referral_code', referral_code)
      .is('referred_id', null)
      .single();

    if (!referral) {
      return new Response(
        JSON.stringify({ error: 'Invalid or already used referral code' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Prevent self-referral
    if (referral.referrer_id === new_customer_id) {
      return new Response(
        JSON.stringify({ error: 'Cannot use your own referral code' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Update referral with referred user
    await supabase
      .from('referrals')
      .update({
        referred_id: new_customer_id,
        status: 'completed',
        reward_given: true,
      })
      .eq('id', referral.id);

    // Award 50 bonus points to both referrer and referred user on their first card
    const bonusPoints = 50;

    // Get first card for referrer
    const { data: referrerCard } = await supabase
      .from('customer_cards')
      .select('id, current_points')
      .eq('customer_id', referral.referrer_id)
      .order('created_at', { ascending: true })
      .limit(1)
      .single();

    if (referrerCard) {
      await supabase
        .from('customer_cards')
        .update({ current_points: referrerCard.current_points + bonusPoints })
        .eq('id', referrerCard.id);

      await supabase.from('transactions').insert({
        card_id: referrerCard.id,
        type: 'points_add',
        value: bonusPoints,
        validated_by: 'manual',
      });
    }

    // Get first card for referred user
    const { data: referredCard } = await supabase
      .from('customer_cards')
      .select('id, current_points')
      .eq('customer_id', new_customer_id)
      .order('created_at', { ascending: true })
      .limit(1)
      .single();

    if (referredCard) {
      await supabase
        .from('customer_cards')
        .update({ current_points: referredCard.current_points + bonusPoints })
        .eq('id', referredCard.id);

      await supabase.from('transactions').insert({
        card_id: referredCard.id,
        type: 'points_add',
        value: bonusPoints,
        validated_by: 'manual',
      });
    }

    return new Response(
      JSON.stringify({ success: true, bonus_points: bonusPoints }),
      {
        status: 200,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      }
    );
  } catch (err) {
    return new Response(
      JSON.stringify({ error: (err as Error).message }),
      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }
});

